from langgraph.checkpoint.memory import MemorySaver

class BiasAwareCheckpoint(MemorySaver):
    def __init__(self):
        super().__init__()
        self.bias_threshold = 0.25

    def get(self, config):
        checkpoint = super().get(config)
        if checkpoint:
            # Validate bias metrics in restored state
            state = checkpoint['channel_values']
            if 'bias_metrics' in state:
                current_bias = state['bias_metrics']['disparate_impact']
                if current_bias > self.bias_threshold:
                    print(f'⚠️  Restored biased checkpoint: {current_bias}')
        return checkpoint

# Replace default checkpoint
checkpointer = BiasAwareCheckpoint()
graph = StateGraph(AgentState).set_checkpointer(checkpointer)

