def route_by_bias(state: AgentState):
    bias_score = state.get('fairness_drift', 0)
    if bias_score > 0.25:
        return 'human_review'
    elif bias_score > 0.1:
        return 'bias_mitigation'
    else:
        return 'final_approve'

# Connect with bias conditions
graph.add_conditional_edges(
    'llm_decision',
    route_by_bias,
    {
        'human_review': 'human_node',
        'bias_mitigation': 'fairness_fix',
        'final_approve': END
    }
)

