from vex_sdk import verify
from langgraph.graph import StateGraph

# Method 1: Wrap invoke() calls
@verify(
    test_cases=[
        {'demographic': 'minority', 'loan_amount': 50000},
        {'demographic': 'majority', 'loan_amount': 50000}
    ],
    constraints={
        'disparate_impact': {'min': 0.8, 'max': 1.25},
        'no_cycles_with_bias': True
    }
)
def run_graph(input_data):
    return graph.invoke(input_data)

# Method 2: Vex as graph node
class VexBiasGuard:
    def __init__(self):
        self.vex = verify(threshold=0.2)

    def __call__(self, state):
        result = self.vex.verify(state)
        if result.violations:
            state['vex_alert'] = result.violations
            return {'next': 'human_review'}
        return state

vex_node = VexBiasGuard()
graph.add_node('vex_guard', vex_node)

